'use client';

import { useState } from 'react';
import { Plus, Pencil, Trash2, Tag, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog';
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { Badge } from '@/components/ui/badge';
import { useWhatsAppLabels } from '@/hooks/useWhatsAppLabels';
import type { WhatsAppLabel } from '@/types/whatsapp';

const PRESET_COLORS = [
    { name: 'Vermelho', value: '#ef4444' },
    { name: 'Laranja', value: '#f97316' },
    { name: 'Amarelo', value: '#eab308' },
    { name: 'Verde', value: '#22c55e' },
    { name: 'Azul', value: '#3b82f6' },
    { name: 'Roxo', value: '#a855f7' },
    { name: 'Rosa', value: '#ec4899' },
    { name: 'Cinza', value: '#6b7280' },
];

export function LabelManager() {
    const {
        labels,
        isLoading,
        createLabel,
        updateLabel,
        deleteLabel,
        isCreating,
        isUpdating,
        isDeleting
    } = useWhatsAppLabels();

    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingLabel, setEditingLabel] = useState<WhatsAppLabel | null>(null);
    const [name, setName] = useState('');
    const [description, setDescription] = useState('');
    const [color, setColor] = useState(PRESET_COLORS[0].value);

    const resetForm = () => {
        setEditingLabel(null);
        setName('');
        setDescription('');
        setColor(PRESET_COLORS[0].value);
    };

    const handleOpenDialog = (label?: WhatsAppLabel) => {
        if (label) {
            setEditingLabel(label);
            setName(label.name);
            setDescription(label.description || '');
            setColor(label.color);
        } else {
            resetForm();
        }
        setIsDialogOpen(true);
    };

    const handleSave = async () => {
        if (!name.trim()) return;

        try {
            if (editingLabel) {
                await updateLabel({
                    labelId: editingLabel.id,
                    updates: { name, description, color },
                });
            } else {
                await createLabel({
                    name,
                    description,
                    color,
                });
            }
            setIsDialogOpen(false);
            resetForm();
        } catch (error) {
            console.error(error);
        }
    };

    if (isLoading) {
        return (
            <div className="flex justify-center p-8">
                <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
        );
    }

    return (
        <div className="space-y-4">
            <div className="flex justify-between items-center">
                <h4 className="text-sm font-medium text-muted-foreground">
                    {labels.length} Etiquetas cadastradas
                </h4>
                <Button onClick={() => handleOpenDialog()} size="sm">
                    <Plus className="h-4 w-4 mr-2" />
                    Nova Etiqueta
                </Button>
            </div>

            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {labels.map((label) => (
                    <div
                        key={label.id}
                        className="flex items-center justify-between p-3 border rounded-lg bg-card hover:bg-muted/50 transition-colors"
                    >
                        <div className="flex items-center gap-3">
                            <div
                                className="w-4 h-4 rounded-full border border-black/10 shadow-sm"
                                style={{ backgroundColor: label.color }}
                            />
                            <div>
                                <p className="font-medium text-sm">{label.name}</p>
                                {label.description && (
                                    <p className="text-xs text-muted-foreground truncate max-w-[150px]">
                                        {label.description}
                                    </p>
                                )}
                            </div>
                        </div>
                        <div className="flex items-center gap-1">
                            <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8"
                                onClick={() => handleOpenDialog(label)}
                            >
                                <Pencil className="h-4 w-4 text-muted-foreground" />
                            </Button>

                            <AlertDialog>
                                <AlertDialogTrigger asChild>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        className="h-8 w-8 text-destructive hover:text-destructive"
                                    >
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                </AlertDialogTrigger>
                                <AlertDialogContent>
                                    <AlertDialogHeader>
                                        <AlertDialogTitle>Excluir etiqueta?</AlertDialogTitle>
                                        <AlertDialogDescription>
                                            Esta ação não pode ser desfeita. A etiqueta "{label.name}" será removida de todas as conversas.
                                        </AlertDialogDescription>
                                    </AlertDialogHeader>
                                    <AlertDialogFooter>
                                        <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                        <AlertDialogAction
                                            onClick={() => deleteLabel(label.id)}
                                            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                                        >
                                            {isDeleting ? (
                                                <Loader2 className="h-4 w-4 animate-spin" />
                                            ) : (
                                                'Excluir'
                                            )}
                                        </AlertDialogAction>
                                    </AlertDialogFooter>
                                </AlertDialogContent>
                            </AlertDialog>
                        </div>
                    </div>
                ))}

                {labels.length === 0 && (
                    <div className="col-span-full border border-dashed rounded-lg p-8 text-center text-muted-foreground">
                        <Tag className="h-8 w-8 mx-auto mb-2 opacity-50" />
                        <p>Nenhuma etiqueta criada.</p>
                        <Button
                            variant="link"
                            onClick={() => handleOpenDialog()}
                        >
                            Criar a primeira
                        </Button>
                    </div>
                )}
            </div>

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>
                            {editingLabel ? 'Editar Etiqueta' : 'Nova Etiqueta'}
                        </DialogTitle>
                        <DialogDescription>
                            Configure o nome e a cor para identificar suas conversas.
                        </DialogDescription>
                    </DialogHeader>

                    <div className="space-y-4 py-4">
                        <div className="space-y-2">
                            <label className="text-sm font-medium">Nome</label>
                            <Input
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                placeholder="ex: Cliente Importante"
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium">Descrição (opcional)</label>
                            <Input
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                placeholder="Breve descrição..."
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium">Cor</label>
                            <div className="flex flex-wrap gap-2">
                                {PRESET_COLORS.map((c) => (
                                    <button
                                        key={c.value}
                                        type="button"
                                        onClick={() => setColor(c.value)}
                                        className={`w-8 h-8 rounded-full border-2 transition-all ${color === c.value
                                                ? 'border-foreground scale-110 shadow-md'
                                                : 'border-transparent opacity-70 hover:opacity-100 hover:scale-105'
                                            }`}
                                        style={{ backgroundColor: c.value }}
                                        title={c.name}
                                    />
                                ))}
                            </div>
                        </div>

                        <div className="flex items-center gap-2 pt-2">
                            <span className="text-sm text-muted-foreground">Prévia:</span>
                            <Badge
                                variant="outline"
                                className="text-white border-transparent"
                                style={{ backgroundColor: color }}
                            >
                                {name || 'Nome da Etiqueta'}
                            </Badge>
                        </div>
                    </div>

                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsDialogOpen(false)}>
                            Cancelar
                        </Button>
                        <Button
                            onClick={handleSave}
                            disabled={!name.trim() || isCreating || isUpdating}
                        >
                            {(isCreating || isUpdating) && (
                                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                            )}
                            Salvar
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}
