'use client';

import { ExternalLink, Info } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
    Accordion,
    AccordionContent,
    AccordionItem,
    AccordionTrigger,
} from '@/components/ui/accordion';

export function SetupGuide() {
    return (
        <div className="space-y-4">
            <div className="bg-blue-500/10 text-blue-600 p-4 rounded-lg flex gap-3 text-sm">
                <Info className="h-5 w-5 flex-shrink-0" />
                <p>
                    Para conectar o DashMed Pro ao WhatsApp, você precisa de uma conta no meta for Developers.
                    Este é o método oficial e mais estável.
                </p>
            </div>

            <Accordion type="single" collapsible className="w-full" defaultValue="step-1">
                <AccordionItem value="step-1">
                    <AccordionTrigger>1. Criar App no Meta</AccordionTrigger>
                    <AccordionContent className="text-sm text-muted-foreground space-y-2">
                        <p>
                            Acesse o <a href="https://developers.facebook.com/" target="_blank" rel="noopener noreferrer" className="text-primary hover:underline inline-flex items-center">Meta for Developers <ExternalLink className="h-3 w-3 ml-1" /></a> e crie um novo app.
                        </p>
                        <p>Selecione "Outro" &gt; "Business" como tipo de app.</p>
                    </AccordionContent>
                </AccordionItem>

                <AccordionItem value="step-2">
                    <AccordionTrigger>2. Configurar WhatsApp</AccordionTrigger>
                    <AccordionContent className="text-sm text-muted-foreground space-y-2">
                        <p>No painel do app, adicione o produto "WhatsApp".</p>
                        <p>Acesse a seção "API Setup" no menu lateral.</p>
                    </AccordionContent>
                </AccordionItem>

                <AccordionItem value="step-3">
                    <AccordionTrigger>3. Obter Credenciais</AccordionTrigger>
                    <AccordionContent className="text-sm text-muted-foreground space-y-2">
                        <p>Na página API Setup, você encontrará:</p>
                        <ul className="list-disc list-inside ml-2 space-y-1">
                            <li><strong>Phone Number ID</strong>: Copie este número.</li>
                            <li><strong>Temporary Access Token</strong>: Para testes (dura 24h).</li>
                        </ul>
                        <p className="mt-2 text-xs bg-yellow-500/10 text-yellow-600 p-2 rounded">
                            Para produção, você precisará configurar um Token Permanente do Sistema.
                        </p>
                    </AccordionContent>
                </AccordionItem>
            </Accordion>

            <div className="pt-4 flex justify-end">
                <Button variant="outline" asChild>
                    <a
                        href="https://developers.facebook.com/docs/whatsapp/cloud-api/get-started"
                        target="_blank"
                        rel="noopener noreferrer"
                    >
                        Documentação Oficial <ExternalLink className="ml-2 h-4 w-4" />
                    </a>
                </Button>
            </div>
        </div>
    );
}
