'use client';

/**
 * Formulário de credenciais do WhatsApp Business API
 */

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Loader2, Eye, EyeOff, Save, CheckCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import {
    Card,
    CardContent,
    CardDescription,
    CardHeader,
    CardTitle,
} from '@/components/ui/card';
import {
    Form,
    FormControl,
    FormDescription,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/components/ui/form';
import { useWhatsAppConfig } from '@/hooks/useWhatsAppConfig';
import type { WhatsAppConfig } from '@/types/whatsapp';

const credentialsSchema = z.object({
    phone_number_id: z.string().min(1, 'Phone Number ID é obrigatório'),
    business_account_id: z.string().optional(),
    access_token: z.string().min(1, 'Access Token é obrigatório'),
    webhook_verify_token: z.string().optional(),
    is_active: z.boolean(),
});

type CredentialsFormValues = z.infer<typeof credentialsSchema>;

interface CredentialsFormProps {
    config: WhatsAppConfig | null | undefined;
    onSuccess?: (webhookUrl: string, verifyToken: string) => void;
}

export function CredentialsForm({ config, onSuccess }: CredentialsFormProps) {
    const [showToken, setShowToken] = useState(false);
    const { validateCredentials, isValidating } = useWhatsAppConfig();

    const form = useForm<CredentialsFormValues>({
        resolver: zodResolver(credentialsSchema),
        defaultValues: {
            phone_number_id: config?.phone_number_id || '',
            business_account_id: config?.business_account_id || '',
            access_token: '',
            webhook_verify_token: config?.webhook_verify_token || '',
            is_active: config?.is_active ?? true,
        },
    });

    const onSubmit = async (values: CredentialsFormValues) => {
        try {
            // Validar e salvar credenciais (o hook faz as duas coisas)
            const result = await validateCredentials({
                phone_number_id: values.phone_number_id,
                access_token: values.access_token,
                business_account_id: values.business_account_id || undefined,
            });

            if (result?.success && onSuccess) {
                onSuccess(result.webhook_url, result.config.webhook_verify_token || '');
            }
        } catch (error: unknown) {
            const errorMessage = error instanceof Error ? error.message : 'Erro desconhecido';
            form.setError('access_token', {
                message: errorMessage,
            });
        }
    };

    return (
        <Card>
            <CardHeader>
                <CardTitle className="flex items-center gap-2">
                    Credenciais da API
                    {config?.is_active && (
                        <CheckCircle className="h-5 w-5 text-green-500" />
                    )}
                </CardTitle>
                <CardDescription>
                    Configure as credenciais do WhatsApp Business API obtidas no Meta Developers
                </CardDescription>
            </CardHeader>
            <CardContent>
                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        <FormField
                            control={form.control}
                            name="phone_number_id"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Phone Number ID</FormLabel>
                                    <FormControl>
                                        <Input
                                            placeholder="123456789012345"
                                            {...field}
                                        />
                                    </FormControl>
                                    <FormDescription>
                                        Encontrado em WhatsApp &gt; API Setup no Meta Business Suite
                                    </FormDescription>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <FormField
                            control={form.control}
                            name="business_account_id"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Business Account ID (opcional)</FormLabel>
                                    <FormControl>
                                        <Input
                                            placeholder="987654321098765"
                                            {...field}
                                        />
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <FormField
                            control={form.control}
                            name="access_token"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Access Token</FormLabel>
                                    <FormControl>
                                        <div className="relative">
                                            <Input
                                                type={showToken ? 'text' : 'password'}
                                                placeholder={config ? '••••••••••••' : 'EAAxxxxxxxxxx...'}
                                                {...field}
                                            />
                                            <Button
                                                type="button"
                                                variant="ghost"
                                                size="icon"
                                                className="absolute right-0 top-0 h-full px-3"
                                                onClick={() => setShowToken(!showToken)}
                                            >
                                                {showToken ? (
                                                    <EyeOff className="h-4 w-4" />
                                                ) : (
                                                    <Eye className="h-4 w-4" />
                                                )}
                                            </Button>
                                        </div>
                                    </FormControl>
                                    <FormDescription>
                                        Token permanente ou temporário do Meta Business Suite
                                    </FormDescription>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <FormField
                            control={form.control}
                            name="webhook_verify_token"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Webhook Verify Token (opcional)</FormLabel>
                                    <FormControl>
                                        <Input
                                            placeholder="meu_token_secreto_123"
                                            {...field}
                                        />
                                    </FormControl>
                                    <FormDescription>
                                        Token usado para verificar o webhook no Meta
                                    </FormDescription>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <FormField
                            control={form.control}
                            name="is_active"
                            render={({ field }) => (
                                <FormItem className="flex items-center justify-between rounded-lg border p-4">
                                    <div className="space-y-0.5">
                                        <FormLabel className="text-base">Ativar integração</FormLabel>
                                        <FormDescription>
                                            Habilita o envio e recebimento de mensagens
                                        </FormDescription>
                                    </div>
                                    <FormControl>
                                        <Switch
                                            checked={field.value}
                                            onCheckedChange={field.onChange}
                                        />
                                    </FormControl>
                                </FormItem>
                            )}
                        />

                        <Button
                            type="submit"
                            className="w-full"
                            disabled={isValidating}
                        >
                            {isValidating ? (
                                <>
                                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                                    Validando e salvando...
                                </>
                            ) : (
                                <>
                                    <Save className="h-4 w-4 mr-2" />
                                    Salvar Configuração
                                </>
                            )}
                        </Button>
                    </form>
                </Form>
            </CardContent>
        </Card>
    );
}
