'use client';

import { useWhatsAppConfig } from '@/hooks/useWhatsAppConfig';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { CredentialsForm } from '@/components/whatsapp/settings/CredentialsForm';
import { SetupGuide } from '@/components/whatsapp/settings/SetupGuide';
import { LabelManager } from '@/components/whatsapp/settings/LabelManager';
import {
    Card,
    CardContent,
    CardDescription,
    CardHeader,
    CardTitle,
} from '@/components/ui/card';
import { Loader2 } from 'lucide-react';

export function WhatsAppSettingsClient() {
    const { config, isLoading } = useWhatsAppConfig();

    if (isLoading) {
        return (
            <div className="flex items-center justify-center p-8">
                <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold tracking-tight">Configurações do WhatsApp</h1>

            <Tabs defaultValue="connection" className="space-y-4">
                <TabsList>
                    <TabsTrigger value="connection">Conexão</TabsTrigger>
                    <TabsTrigger value="labels">Etiquetas</TabsTrigger>
                    <TabsTrigger value="ai">Inteligência Artificial</TabsTrigger>
                </TabsList>

                <TabsContent value="connection" className="space-y-4">
                    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
                        <div className="col-span-4">
                            <CredentialsForm config={config} />
                        </div>

                        <div className="col-span-3">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Como Conectar</CardTitle>
                                    <CardDescription>
                                        Guia passo a passo para configurar a API Oficial.
                                    </CardDescription>
                                </CardHeader>
                                <CardContent>
                                    <SetupGuide />
                                </CardContent>
                            </Card>
                        </div>
                    </div>
                </TabsContent>

                <TabsContent value="labels">
                    <Card>
                        <CardHeader>
                            <CardTitle>Gerenciador de Etiquetas</CardTitle>
                            <CardDescription>
                                Organize suas conversas com etiquetas coloridas.
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            <LabelManager />
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="ai">
                    <Card>
                        <CardHeader>
                            <CardTitle>Configuração da IA (Em Breve)</CardTitle>
                            <CardDescription>
                                Personalize como a IA responde e categoriza leads.
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="p-4 border rounded bg-muted/20 text-center">
                                <p className="text-muted-foreground">O módulo de IA estará disponível na próxima atualização.</p>
                            </div>
                        </CardContent>
                    </Card>
                </TabsContent>
            </Tabs>
        </div>
    );
}
